import{_ as a,H as t,f as s,i as o}from"./chunks/framework.nN4pLK1d.js";const m=JSON.parse('{"title":"SMS RFM","description":"","frontmatter":{},"headers":[],"relativePath":"packages/rcml/sms/concepts/sms-rfm.md","filePath":"packages/rcml/sms/concepts/sms-rfm.md"}'),n={name:"packages/rcml/sms/concepts/sms-rfm.md"};function r(i,e,l,c,d,p){return t(),s("div",null,[...e[0]||(e[0]=[o(`<h1>SMS RFM</h1><p><strong>SMS RFM</strong> (SMS Rule Flavor Markdown) is the source text format used inside an <code>&lt;rc-sms&gt;</code> element. It is a compact, human-readable string that compiles to the <a href="./sms-document.html"><code>SmsContentJson</code></a> tree. Writing SMS RFM is far more concise than constructing <code>SmsContentJson</code> by hand, and it is the form the XML representation of an SMS template stores in the body of <code>&lt;rc-sms&gt;</code>.</p><p>This page describes the format conceptually — what constructs it has and how they map to the document model. For the functions that parse and serialise it, see <a href="./../building-programmatically.html">Building programmatically</a>.</p><h2 id="what-sms-rfm-contains" tabindex="-1">What SMS RFM contains <a class="header-anchor" href="#what-sms-rfm-contains" aria-label="Permalink to &quot;What SMS RFM contains&quot;">​</a></h2><p>An SMS RFM string is built from four constructs:</p><ol><li><strong>Paragraphs</strong> — separated by blank lines.</li><li><strong>Hard breaks</strong> — forced line breaks inside a paragraph.</li><li><strong>Placeholders</strong> — dynamic values substituted at send time.</li><li><strong>Links</strong> — text that becomes a hyperlink with tracking and shortening flags.</li></ol><p>That is the entire format. Plain text written between these constructs becomes text nodes verbatim.</p><h2 id="paragraphs" tabindex="-1">Paragraphs <a class="header-anchor" href="#paragraphs" aria-label="Permalink to &quot;Paragraphs&quot;">​</a></h2><p>A paragraph is a block of text on consecutive lines. A blank line ends one paragraph and starts the next:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>First paragraph.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Second paragraph.</span></span></code></pre></div><p>See <a href="./../content/nodes/paragraph.html"><code>paragraph</code></a> for the node reference.</p><h2 id="hard-breaks" tabindex="-1">Hard breaks <a class="header-anchor" href="#hard-breaks" aria-label="Permalink to &quot;Hard breaks&quot;">​</a></h2><p>A hard break is a line break that stays inside the same paragraph. Write a backslash at the end of a line, or two trailing spaces, to insert one:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>First line\\</span></span>
<span class="line"><span>Second line — same paragraph</span></span></code></pre></div><p>See <a href="./../content/nodes/hardbreak.html"><code>hardbreak</code></a> for the node reference and the distinction between hard breaks and paragraph boundaries.</p><h2 id="placeholders" tabindex="-1">Placeholders <a class="header-anchor" href="#placeholders" aria-label="Permalink to &quot;Placeholders&quot;">​</a></h2><p>A placeholder inserts a dynamic value — a subscriber field, custom field, account attribute, formatted date, fetched remote content, or system-managed link URL.</p><p>The recommended form is the <code>::placeholder{…}</code> directive:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hi ::placeholder{type=&quot;Subscriber&quot; original=&quot;[Subscriber:FirstName]&quot; name=&quot;First name&quot;}!</span></span></code></pre></div><p>Six token types are available: <code>Subscriber</code>, <code>User</code>, <code>CustomField</code>, <code>Date</code>, <code>RemoteContent</code>, and <code>Link</code>. The <code>original</code> attribute holds the backend token (in <code>[Type:Name]</code> format) the Rule platform substitutes at send time.</p><p>Plain-text <code>[Type:Name]</code> tokens belong inside the <code>original</code> attribute of a <code>::placeholder{…}</code> directive (as shown above) or inside a URL value such as <code>href=&quot;[Link:Unsubscribe]&quot;</code>. The parser does also accept a bare <code>[Type:Name]</code> token as a backward-compatible shorthand and produces an equivalent placeholder node from it, but the <code>::placeholder{…}</code> directive is the recommended form for body content because it carries the full <code>name</code> / <code>value</code> / <code>max-length</code> attributes the editor expects.</p><p>See <a href="./../content/nodes/placeholder.html"><code>placeholder</code></a> for the full attribute table, the catalogue of all six token types, and per-token examples.</p><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><p>A link wraps a span of text in a hyperlink. The <code>:link[…]{…}</code> directive provides the destination URL, a tracking flag, and a URL-shortening flag:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Click :link[here]{href=&quot;https://example.com&quot; track=&quot;true&quot; shorten=&quot;true&quot;} to track your order.</span></span></code></pre></div><p>Inside <code>href</code> a plain-text <code>[Link:…]</code> token is the right form for system-managed URLs:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>:link[Unsubscribe]{href=&quot;[Link:Unsubscribe]&quot; track=&quot;false&quot; shorten=&quot;false&quot;}</span></span></code></pre></div><p>See the <a href="./../content/marks/link.html">link mark</a> page for the full attribute reference.</p><h2 id="a-complete-example" tabindex="-1">A complete example <a class="header-anchor" href="#a-complete-example" aria-label="Permalink to &quot;A complete example&quot;">​</a></h2><p>A short marketing message exercising all four constructs:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hi ::placeholder{type=&quot;Subscriber&quot; original=&quot;[Subscriber:FirstName]&quot; name=&quot;First name&quot;},\\</span></span>
<span class="line"><span>your order ::placeholder{type=&quot;CustomField&quot; original=&quot;[CustomField:Order.Id]&quot; name=&quot;Order.Id&quot;} has shipped.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Track it here: :link[track shipment]{href=&quot;https://example.com/track/[CustomField:Order.Id]&quot; track=&quot;true&quot; shorten=&quot;true&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Reply STOP to unsubscribe.</span></span></code></pre></div><p>This compiles to a three-paragraph <code>SmsContentJson</code> document — a greeting with a hard break and two placeholders, a tracking link, and a footer — exactly the shape described on the <a href="./sms-document.html">SMS document</a> page.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../content/nodes/paragraph.html"><code>paragraph</code></a> — paragraph node reference</li><li><a href="./../content/nodes/hardbreak.html"><code>hardbreak</code></a> — hard break node reference</li><li><a href="./../content/nodes/text.html"><code>text</code></a> — text node reference</li><li><a href="./../content/nodes/placeholder.html"><code>placeholder</code></a> — placeholder node reference and token catalogue</li><li><a href="./../content/marks/link.html">link mark</a> — link mark reference</li><li><a href="./sms-document.html">SMS document</a> — the document model SMS RFM compiles to</li><li><a href="./../building-programmatically.html">Building programmatically</a> — <code>smsRfmToJson</code> / <code>jsonToSmsRfm</code> and the rest of the API</li></ul>`,34)])])}const u=a(n,[["render",r]]);export{m as __pageData,u as default};
